--- a/src/njs_vmcode.c
+++ b/src/njs_vmcode.c
@@ -797,8 +797,25 @@ next:
                 pnext = (njs_vmcode_prop_next_t *) pc;
                 retval = njs_scope_value(vm, pnext->retval);

+                /* Validate that value2 contains a data iterator. */
+                if (njs_slow_path(value2 == NULL
+                                  || !njs_is_data(value2, NJS_DATA_TAG_ARRAY_ITERATOR)
+                                  || value2->data.u.next == NULL))
+                {
+                    /* Invalid iterator: return undefined and continue. */
+                    njs_set_undefined(retval);
+                    ret = sizeof(njs_vmcode_prop_next_t);
+                    break;
+                }
+
                 next = value2->data.u.next;

+                if (njs_slow_path(next->array == NULL)) {
+                    njs_set_undefined(retval);
+                    ret = sizeof(njs_vmcode_prop_next_t);
+                    break;
+                }
+
                 if (next->index < next->array->length) {
                     *retval = next->array->start[next->index++];

@@ -1430,7 +1447,8 @@ njs_vmcode_property_foreach(njs_vm_t *vm, njs_value_t *object,
         return NJS_ERROR;
     }

-    vm->retval.data.u.next = next;
+    /* Initialize vm->retval as a DATA value that carries the iterator. */
+    njs_set_data(&vm->retval, next, NJS_DATA_TAG_ARRAY_ITERATOR);

     code = (njs_vmcode_prop_foreach_t *) pc;

