+		if (!orig) { gf_free(no_emulation_buf); continue; }
 		gf_bs_read_data(orig, no_emulation_buf, no_emulation_buf_size);
 		gf_bs_seek(orig, 0);
 		mod = gf_bs_new(NULL, 0, GF_BITSTREAM_WRITE);
+		if (!mod) { gf_bs_del(orig); orig = NULL; gf_free(no_emulation_buf); continue; }

 		/*copy over till vui flag*/
-		assert(bit_offset >= 8);
+		/* ensure bit_offset is sane and enough bits are available */
+		if (bit_offset < 8 || gf_bs_bits_available(orig) < (bit_offset - 8)) {
+			/* invalid offset or not enough bits, skip rewriting */
+			gf_bs_del(orig); orig = NULL; gf_bs_del(mod); gf_free(no_emulation_buf); continue;
+		}
 		while (bit_offset - 8/*bit_offset doesn't take care of the first byte (NALU type)*/) {
 			flag = gf_bs_read_int(orig, 1);
 			gf_bs_write_int(mod, flag, 1);
@@ -6915,6 +6933,7 @@ GF_Err gf_avc_change_vui(GF_AVCConfig *avcc, GF_VUIInfo *vui_info)
 		slc->size = gf_media_nalu_add_emulation_bytes(no_emulation_buf, slc->data + 1, flag) + 1;

 		gf_bs_del(mod);
+		/* gf_bs_get_content returned a buffer in no_emulation_buf which needs to be freed */
 		gf_free(no_emulation_buf);
