@@ -0,0 +1,68 @@
+#include <stdio.h>
+#include <stdlib.h>
+
+// Simulate the GetPixelChannel function
+typedef unsigned int Quantum;
+typedef enum {
+    UndefinedPixelTrait = 0,
+    UpdatePixelTrait = 1
+} PixelTrait;
+
+typedef struct {
+    PixelTrait traits;
+    int offset;
+} ChannelMapEntry;
+
+typedef struct {
+    ChannelMapEntry channel_map[5];
+    int number_channels;
+} Image;
+
+typedef enum {
+    RedPixelChannel = 0,
+    GreenPixelChannel = 1,
+    BluePixelChannel = 2,
+    AlphaPixelChannel = 3,
+    IndexPixelChannel = 4
+} PixelChannel;
+
+static inline Quantum GetPixelChannel(const Image *image,
+  const PixelChannel channel, const Quantum *pixel)
+{
+  if (image->channel_map[channel].traits == UndefinedPixelTrait)
+    return((Quantum) 0);
+  return(pixel[image->channel_map[channel].offset]);
+}
+
+int main() {
+    // Test case: image has RGB channels, next has Gray+Alpha
+    Image image = {0};
+    Image next = {0};
+    
+    // Image has 3 channels: R,G,B
+    image.number_channels = 3;
+    image.channel_map[RedPixelChannel] = (ChannelMapEntry){UpdatePixelTrait, 0};
+    image.channel_map[GreenPixelChannel] = (ChannelMapEntry){UpdatePixelTrait, 1};
+    image.channel_map[BluePixelChannel] = (ChannelMapEntry){UpdatePixelTrait, 2};
+    image.channel_map[AlphaPixelChannel] = (ChannelMapEntry){UndefinedPixelTrait, 0};
+    
+    // Next has 2 channels: Gray, Alpha
+    next.number_channels = 2;
+    next.channel_map[RedPixelChannel] = (ChannelMapEntry){UpdatePixelTrait, 0}; // Gray at offset 0
+    next.channel_map[GreenPixelChannel] = (ChannelMapEntry){UndefinedPixelTrait, 0};
+    next.channel_map[BluePixelChannel] = (ChannelMapEntry){UndefinedPixelTrait, 0};
+    next.channel_map[AlphaPixelChannel] = (ChannelMapEntry){UpdatePixelTrait, 1}; // Alpha at offset 1
+    
+    Quantum pixel[2] = {100, 200}; // Gray=100, Alpha=200
+    
+    // OLD BUGGY CODE: GetPixelChannel(&image, BluePixelChannel, pixel)
+    // Would access pixel[image.channel_map[BluePixelChannel].offset] = pixel[2]
+    // OUT OF BOUNDS!
+    
+    // NEW FIXED CODE: GetPixelChannel(&next, BluePixelChannel, pixel)
+    // Returns 0 because next.channel_map[BluePixelChannel].traits == UndefinedPixelTrait
+    Quantum result = GetPixelChannel(&next, BluePixelChannel, pixel);
+    print

